                {"swissGerman": "sini Qualitäte", "german": "seine Qualitäten", "explanation": "'sini' = 'seine'. Swiss possessive."},
                {"swissGerman": "Do häsch du rächt", "german": "Da hast du recht", "explanation": "Acknowledging someone's point."},
